args.sparql:
SELECT ?director WHERE {
  ?episode wdt:P31 wd:Q21191272 ;
           wdt:P5002 1 ;
           wdt:P1364 1 ;
           wdt:P361 wd:Q56274745 ;
           wdt:P57 ?director .
}

SELECT ?directorLabel WHERE {
  wd:Q134879295 wdt:P57 ?director .
  ?director rdfs:label ?directorLabel .
  FILTER(LANG(?directorLabel) = 'en')
}

SELECT ?director ?directorLabel WHERE {
  wd:Q134879295 wdt:P57 ?director .
  ?director rdfs:label ?directorLabel .
  FILTER (LANG(?directorLabel) = 'en')
}
